/** Pre-compiled mock_option module bytecode (hex). See mock_option/ in repo root. */
export const OPTION_COIN_TEMPLATE_HEX =
  ''

export const TEMPLATE_OTW_NAME = 'MOCK_OPTION'
export const TEMPLATE_MODULE_NAME = 'mock_option'
export const TEMPLATE_SYMBOL = 'MOPTION'

export function hexToBytes(hex: string): Uint8Array {
  const bytes = new Uint8Array(hex.length / 2)
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = Number.parseInt(hex.slice(i, i + 2), 16)
  }
  return bytes
}

export function bytesToHex(bytes: Uint8Array): string {
  return Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
}
